rawInput.content:
/**
 * Artifact type interfaces for fresh ACPX round artifacts.
 */

/**
 * Base interface for all artifacts.
 */
export interface Artifact {
  readonly id: string;
  readonly version: string;
  readonly createdAt: number;
}

/**
 * Metadata associated with an artifact.
 */
export interface ArtifactMetadata {
  readonly artifactId: string;
  readonly name: string;
  readonly description: string;
  readonly tags: readonly string[];
  readonly round: number;
}

/**
 * Schema definition for artifact validation.
 */
export interface Schema {
  readonly type: string;
  readonly properties: Record<string, unknown>;
  readonly required: readonly string[];
}

/**
 * Artifact produced during a round execution.
 */
export interface RoundArtifact extends Artifact {
  readonly round: number;
  readonly inputSchema: Schema;
  readonly outputSchema: Schema;
  readonly data: unknown;
  readonly metadata: ArtifactMetadata;
}

/**
 * Enum for common artifact types.
 */
export enum ArtifactType {
  Round = "round",
  Metadata = "metadata",
  Schema = "schema",
}

